member.example:
Bind the input type of a TMP_InputField using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldInputTypeBinder _inputType;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_InputField.InputType _inputType;
    }


Bind the input type of a TMP_InputField by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldInputTypeBinder InputType =>
            new(_inputField);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_InputField.InputType _inputType;
    }

Switch the input type of a TMP_InputField between two values using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldInputTypeSwitcherBinder _isPassword;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isPassword;
    }


Switch the input type of a TMP_InputField between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldInputTypeSwitcherBinder IsPassword => new(
            _inputField,
            TMP_InputField.InputType.Password,
            TMP_InputField.InputType.Standard);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isPassword;
    }
